        @mcp.tool()
        async def threed_create_scene(
            output_filename: str,
            primitives: list[str] | None = None,
        ) -> dict:
            """
            Create a simple 3D scene with specified primitives and save it to a file.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                output_filename: Bare filename for the resulting 3D scene (e.g. "scene.obj").
                primitives: Optional list of primitive names to add to the scene. Supported names are
                            "box", "sphere", and "cylinder". If omitted or None, an empty scene is created.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file
                }
        
            Raises:
                FileNotFoundError: If a required input file is missing (not applicable here but kept for consistency).
                ValueError: If an unsupported primitive name is supplied.
                Exception: Any unexpected error from Aspose is caught and reported in the return dict.
        
            Example:
                result = await threed_create_scene(
                    output_filename="my_scene.obj",
                    primitives=["box", "sphere"]
                )
                # result => {"status":"success","message":"Scene saved","output_filename":"my_scene.obj"}
            """
            # ----------------------------------------------------------------------
            # Sanitize and resolve the output filename (no Aspose import yet)
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # Clean the filename supplied by the caller
            output_filename = Path(output_filename.strip().replace('\x00', '')).name
        
            # Resolve where the file will be written; if None (should not happen here) use a temp file
            resolved_output = (
                get_safe_path(output_filename)
                if output_filename
                else str(temp_output_path("aspose_threed_result", ".obj"))
            )
        
            # Ensure the target directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            try:
                # ------------------------------------------------------------------
                # Import Aspose after all path handling is complete
                # ------------------------------------------------------------------
                from aspose.threed import Scene
                from aspose.threed.entities import Box, Sphere, Cylinder
        
                # Create an empty scene
                scene = Scene()
        
                # Map primitive names to Aspose entity constructors
                primitive_map = {
                    "box": Box,
                    "sphere": Sphere,
                    "cylinder": Cylinder,
                }
        
                # Add requested primitives
                if primitives:
                    for name in primitives:
                        key = name.lower()
                        if key not in primitive_map:
                            raise ValueError(f"Unsupported primitive: '{name}'. Supported: {list(primitive_map.keys())}")
                        entity = primitive_map[key]()  # instantiate the entity
                        scene.root_node.create_child_node(key, entity)
        
                # Save the scene to the resolved output path
                scene.save(str(resolved_output))
        
                logger.info("3D scene created and saved to %s", resolved_output)
                return {
                    "status": "success",
                    "message": "Scene saved successfully.",
                    "output_filename": output_filename,
                }
        
            except Exception as exc:  # Catch any Aspose or runtime errors
                logger.error("Failed to create 3D scene: %s", exc, exc_info=True)
                return {
                    "status": "error",
                    "message": str(exc),
                    "output_filename": output_filename,
                }

        @mcp.tool()
        async def threed_get_scene_info(input_filename: str) -> dict:
            """
            Retrieve basic information from a 3D scene file stored on the server.
        
            IMPORTANT: All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') —
            no path, no directory, no drive letter, no slash.
            The file MUST already exist in the server's ASPOSE_FILES_PATH folder.
            Do NOT ask the user to upload a file — files are pre-placed in that folder.
            Output files are written to the same folder; returned output_filename is the bare name only.
        
            Args:
                input_filename: bare filename of the 3D file to analyze, e.g. 'model.obj'.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "node_count": int,
                    "child_names": list[str]
                }
        
            Raises:
                FileNotFoundError: if the specified file does not exist in ASPOSE_FILES_PATH.
                Exception: any unexpected error while processing the scene.
        
            Example:
                result = await threed_get_scene_info("sample.obj")
                # result => {"status":"success","message":"Scene information retrieved successfully.",
                #            "node_count":42,"child_names":["Cube","Sphere"]}
            """
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # Sanitize and resolve the input filename
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            try:
                # Lazy import of Aspose.3D
                from aspose.threed import Scene
        
                # Load the scene from the resolved path
                scene = Scene.from_file(str(resolved_input))
        
                # Recursive node counting
                def count_nodes(node):
                    """
                    Recursively count the total number of nodes in a scene graph.
        
                    Args:
                        node: The current node object, expected to have a ``child_nodes`` attribute
                            that is iterable of child node objects.
        
                    Returns:
                        int: The total count of nodes including the provided ``node`` and all of its descendants.
        
                    Raises:
                        AttributeError: If the ``node`` does not have a ``child_nodes`` attribute.
        
                    Example:
                        >>> total = count_nodes(scene.root_node)
                        >>> print(total)
                        42
                    """
                    total = 1
                    for child in getattr(node, "child_nodes", []):
                        total += count_nodes(child)
                    return total
        
                node_count = count_nodes(scene.root_node)
                child_names = [c.name for c in getattr(scene.root_node, "child_nodes", [])]
        
                return {
                    "status": "success",
                    "message": "Scene information retrieved successfully.",
                    "node_count": node_count,
                    "child_names": child_names,
                }
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to get scene info for %s", input_filename)
                return {"status": "error", "message": str(exc)}

