        @mcp.tool()
        async def threed_merge_scenes(
            base_filename: str,
            merge_filename: str,
            output_filename: str | None = None,
        ) -> dict:
            """
            Merge two 3D scene files into a single GLB.
        
            IMPORTANT: All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') —
            no path, no directory, no drive letter, no slash.
            The file MUST already exist in the server's ASPOSE_FILES_PATH folder.
            Do NOT ask the user to upload a file — files are pre‑placed in that folder.
            Output files are written to the same folder; returned output_filename is the bare name only.
        
            Args:
                base_filename (str): Bare filename of the base scene (e.g. 'base.obj') — must already exist in ASPOSE_FILES_PATH.
                merge_filename (str): Bare filename of the scene to merge into the base (e.g. 'extra.stl') — must already exist.
                output_filename (str | None, optional): Desired bare filename for the merged result. If omitted, a temporary name is generated.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file
                }
        
            Example:
                >>> result = await threed_merge_scenes("base.obj", "extra.stl", "merged.glb")
                >>> result["status"]
                "success"
                >>> result["output_filename"]
                "merged.glb"
        
            Raises:
                FileNotFoundError: If any input file does not exist.
                Exception: For any unexpected errors during processing.
            """
            # ----------------------------------------------------------------------
            # Resolve and validate input filenames (must happen before any Aspose import)
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize and resolve base scene
            base_filename = Path(base_filename.strip().replace("\x00", "")).name
            resolved_base = get_safe_path(base_filename)
            if not Path(resolved_base).is_file():
                raise FileNotFoundError(f"File not found: {base_filename}")
        
            # sanitize and resolve scene to merge
            merge_filename = Path(merge_filename.strip().replace("\x00", "")).name
            resolved_merge = get_safe_path(merge_filename)
            if not Path(resolved_merge).is_file():
                raise FileNotFoundError(f"File not found: {merge_filename}")
        
            # ----------------------------------------------------------------------
            # Resolve output location
            # ----------------------------------------------------------------------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                resolved_output = get_safe_path(output_filename)
            else:
                # temporary filename with .glb extension
                resolved_output = str(temp_output_path("aspose_threed_result", ".glb"))
                output_filename = Path(resolved_output).name
        
            # ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Aspose 3D processing
            # ----------------------------------------------------------------------
            try:
                from aspose.threed import Scene
        
                # load scenes
                base_scene = Scene.from_file(str(resolved_base))
                extra_scene = Scene.from_file(str(resolved_merge))
        
                # merge child nodes safely
                for child in list(extra_scene.root_node.child_nodes):
                    base_scene.root_node.child_nodes.append(child)
        
                # save merged scene
                base_scene.save(str(resolved_output))
        
                return {
                    "status": "success",
                    "message": "Scenes merged successfully.",
                    "output_filename": output_filename,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to merge 3D scenes")
                return {"status": "error", "message": str(exc)}

